import React from "react";
import {
  VerticalTimeline,
  VerticalTimelineElement,
} from "react-vertical-timeline-component";
import "react-vertical-timeline-component/style.min.css";

const experienceData = [
  {
    date: "2022 - Presente",
    title: "Senior Product Manager",
    company: "EY",
    description:
      "Lidero la visión, estrategia y roadmap para una plataforma global de reporte financiero e investigación.",
    skills: ["Agile", "Cloud", "Power BI"],
  },
  {
    date: "2018 - 2022",
    title: "Product Manager",
    company: "J.P. Morgan",
    description:
      "Gestión de productos para integración de datos legacy a cloud, arquitectura event-driven.",
    skills: ["Kafka", "Microservicios", "Azure"],
  },
  {
    date: "2010 - 2018",
    title: "Project Manager",
    company: "ExxonMobil",
    description:
      "Automatización de licencias FlexLM, migración de plataformas monolíticas a AEM.",
    skills: ["DevOps", "AEM", "Automatización"],
  },
  // Agregá más roles aquí...
];

export default function ExperienceTimeline() {
  return (
    <div>
      <h2 className="text-2xl font-bold mb-6 text-center">Mi experiencia laboral</h2>
      <VerticalTimeline>
        {experienceData.map(({ date, title, company, description, skills }, i) => (
          <VerticalTimelineElement
            key={i}
            date={date}
            contentStyle={{ background: "#4f46e5", color: "#fff" }}
            contentArrowStyle={{ borderRight: "7px solid  #4f46e5" }}
            iconStyle={{ background: "#312e81", color: "#fff" }}
          >
            <h3 className="vertical-timeline-element-title">{title}</h3>
            <h4 className="vertical-timeline-element-subtitle">{company}</h4>
            <p>{description}</p>
            <p className="mt-2 font-semibold">Skills:</p>
            <ul className="list-disc list-inside">
              {skills.map((skill, idx) => (
                <li key={idx}>{skill}</li>
              ))}
            </ul>
          </VerticalTimelineElement>
        ))}
      </VerticalTimeline>
    </div>
  );
}
